/* ─── Node component ─── */
function FlowNodeEl({
  node,
  accentColor,
  accentColor2,
  accentColor3,
}: {
  node: FlowNode;
  accentColor: string;
  accentColor2: string;
  accentColor3: string;
}) {
  const variantStyles: Record<FlowNode['variant'], { border: string; bg: string; dot: string; text: string }> = {
    accent: {
      border: `rgba(79,127,255,0.40)`,
      bg: `rgba(79,127,255,0.08)`,
      dot: accentColor,
      text: accentColor,
    },
    purple: {
      border: `rgba(123,92,255,0.30)`,
      bg: `rgba(123,92,255,0.08)`,
      dot: accentColor2,
      text: accentColor2,
    },
    green: {
      border: `rgba(0,212,168,0.30)`,
      bg: `rgba(0,212,168,0.07)`,
      dot: accentColor3,
      text: accentColor3,
    },
    default: {
      border: `rgba(255,255,255,0.07)`,
      bg: `#13151A`,
      dot: '#4A4F65',
      text: '#8A8FA8',
    },
  };

  const s = variantStyles[node.variant];
  const indentPx = node.indent * 48;

  return (
    <div className="flex items-center gap-2.5" style={{ paddingLeft: indentPx }}>
      {node.indent > 0 && (
        <span className="text-[#4A4F65] text-sm flex-shrink-0">↳</span>
      )}
      <div
        className="flex items-center gap-2 rounded-[10px] px-4 py-2.5 text-[12px] font-medium whitespace-nowrap border"
        style={{ background: s.bg, borderColor: s.border, color: s.text }}
      >
        <span className="w-[7px] h-[7px] rounded-full flex-shrink-0" style={{ background: s.dot }} />
        {node.label}
      </div>
    </div>
  );
}

